external_knowledge:
- "hidden gems" metaphorically refers to cities that are less frequented or mentioned;
- "over 50 residents" refers to cities with more than 50 participants;
- "ages that collectively whisper the tale of maturity" metaphorically represents the average age of participants in those cities.

sql:
SELECT city_name
FROM cities
WHERE total_entries > 20;

SELECT city_name 
FROM cities 
WHERE total_participants > 10;

SELECT name, age
FROM participants
WHERE participant_id IN (
  SELECT participant_id
  FROM entries
);

SELECT equipment_name
FROM equipment
WHERE stock_quantity = (SELECT MIN(stock_quantity) FROM equipment);

